window.QB_H8_2U2_L7.push(
  {c:'建国',q:'1971年，联合国大会恢复中国合法席位的决议是第几届联大通过的？',o:['第24届','第25届','第26届','第30届'],a:2,e:'1971年10月，联合国大会第26届会议以76票赞成、35票反对、17票弃权通过第2758号决议，恢复中华人民共和国在联合国的一切合法权利，驱逐台湾蒋介石集团的代表。'},
  {c:'建国',q:'中美关系从敌对走向正常化的根本原因是？',o:['中美双方的意识形态趋于一致','中美两国都有改善关系的战略需要（中国需要打破封锁，美国需要借助中国对抗苏联）','苏联要求中美建交','联合国推动了中美和解'],a:1,e:'中美关系正常化的根本原因是共同的战略需要：中国需要突破美国封锁、改善国际处境；美国需要借助中国制衡苏联、体面退出越南战争。双方战略利益的契合推动了关系正常化。'},
  {c:'建国',q:'"乒乓外交"的特点是？',o:['通过体育比赛决定外交政策','以体育交流为突破口，打破政治坚冰，推动中美关系走向改善','完全替代了正式的外交谈判','证明体育比外交更重要'],a:1,e:'"乒乓外交"（1971年）体现了中国外交的创造性：用非政治手段（体育交流）突破政治僵局，以柔克刚，以小带大，为中美关系改善创造了友好氛围，是外交史上的创举。'},
  {c:'建国',q:'1972年中日邦交正常化后，中日两国关系正常化的意义是？',o:['使日本放弃了侵华历史责任','标志着战后中日长期不正常关系的结束，为中日和平友好条约的签署奠定基础','使日本立即向中国大量赔款','使中国获得了日本全部领土'],a:1,e:'中日邦交正常化（1972年）：结束了战后长期存在的中日政治对立关系，为中日全面正式外交关系奠定基础，1978年进一步签署《中日和平友好条约》，推动了亚太地区的和平稳定。'},
  {c:'建国',q:'中国核武器的研制原则是？',o:['首先核打击','核威慑，但宣布不首先使用核武器','核扩散，提供给盟友','拒绝参与任何核谈判'],a:1,e:'中国研制核武器后，明确宣布承担"不首先使用核武器"的义务，不参与核军备竞赛，不向外国转让核技术，坚持核武器用于防御性的核威慑目的，维护世界战略平衡与和平。'},
  {c:'建国',q:'20世纪70年代中国外交取得突破的国际背景是？',o:['中苏关系改善','美苏争霸，苏联占优，美国战略收缩，需要借助中国制衡苏联','中国综合国力大幅提升','西方国家主动向中国道歉'],a:1,e:'70年代国际背景：苏联实力增强，美国深陷越战泥潭，霸权受挫，需要战略调整；美国意识到孤立中国不符合战略利益，主动寻求改善关系；第三世界国家力量上升，有利于中国恢复联合国席位。'},
  {c:'建国',q:'下列关于中国重返联合国的表述，正确的是？',o:['是中国外交的失败','是中国孤立无援的表现','是众多亚非拉发展中国家支持的结果，体现了中国外交的胜利','主要是美国主导的结果'],a:2,e:'1971年中国恢复联合国席位，主要是众多亚非拉发展中国家大力支持（占联大多数）的结果，体现了和平共处五项原则推动下中国与发展中国家关系的深化，是中国外交的重大胜利。'}
);

