window.QB_H8_2U3_L9.push(
  {c:'建国',q:'农村家庭联产承包责任制的实质是？',o:['土地私有化','在坚持土地集体所有制的前提下，扩大农民自主经营权','恢复个体农民经济','把土地分给农民所有'],a:1,e:'家庭联产承包责任制：土地所有权归集体，使用权承包给农民家庭；农民在完成集体公共积累后，自主安排生产，剩余归己。这在不改变所有制的前提下，极大扩大了农民的生产自主权。'},
  {c:'建国',q:'城市经济体制改革的中心环节是？',o:['建立经济特区','扩大国有企业经营自主权（增强企业活力）','实行土地私有化','发展乡镇企业'],a:1,e:'1984年，城市经济体制改革全面展开，中心环节是增强企业活力，通过政企分开、扩大国有企业自主权（产品自销权、定价权、人事权等），使企业成为相对独立的经济实体，激发市场竞争活力。'},
  {c:'建国',q:'1985年起，城市改革的主要任务是？',o:['土地承包到户','从流通领域入手，扩大企业自主权，推行多种经营模式','学习西方管理','发展资本主义工商业'],a:1,e:'城市经济体制改革从扩大企业自主权入手，逐步推进政企分开、价格双轨制改革、所有制改革等，使国有企业逐步从计划经济的附属品转变为具有市场主体地位的独立法人。'},
  {c:'建国',q:'家庭联产承包责任制的推行，对当时农村最直接的影响是？',o:['土地所有权发生变化','解散了原有的人民公社','极大调动了农民生产积极性，农业生产力得到解放，农业产量大幅提升','只对安徽有效'],a:1,e:'家庭联产承包责任制推行后，农民因与劳动成果直接挂钩而生产积极性高涨，农业生产获得大解放，粮食及各种农副产品产量大幅提升，农民收入迅速增加，农村面貌发生根本变化。'},
  {c:'建国',q:'下列属于对外开放的格局（由先到后）的表述，正确的是？',o:['内地→沿海→沿边','经济特区→沿海开放城市→沿海经济开放区→内地','全面均衡开放','一次性全面开放'],a:1,e:'对外开放格局的形成：①1980年设立深圳等四个经济特区②1984年开放14个沿海城市③开辟沿海经济开放区④1992年进一步开放内地省会等城市和边境城市，形成全方位、多层次、宽领域的格局。'},
  {c:'建国',q:'1985年，城市经济体制改革全面展开，其基本方向是？',o:['从计划经济走向社会主义市场经济方向','恢复计划经济体制','向资本主义经济靠拢','完全私有化'],a:0,e:'城市经济体制改革的基本方向：逐步打破计划经济体制，引入市场竞争机制，扩大企业自主权，推动价格改革，最终目标是建立社会主义市场经济体制（1992年十四大确立）。'},
  {c:'建国',q:'中国经济特区与以往通商口岸的本质区别是？',o:['位置不同','利用外资目的不同','经济特区是主动开放，在中国主权下实行特殊经济政策；通商口岸是被迫开放，带有屈辱性质','没有本质区别'],a:2,e:'经济特区是在中国主权下主动设立，目的是引进外资、技术和管理经验，推动国家现代化建设；而旧中国通商口岸是被迫开放的，丧失了主权，是国家屈辱的体现，性质根本不同。'}
);

